// Build affiliate URLs and add missing fields
const finalProducts = newProducts.map(p => {
  const config = brandConfig[p.brand];
  const [urlTemplate, discountPercent, discountCode] = config;
  const affiliateUrl = urlTemplate.replace("{q}", encodeURIComponent(p.name));

  return {
    ...p,
    image_url: "",
    affiliate_url: affiliateUrl,
    discount_code: discountCode,
    discount_percent: discountPercent,
    in_stock: true,
  };
});

// Read file, insert before closing ];
let content = readFileSync(filePath, "utf-8");

// Build the product strings
const productStrings = finalProducts.map(p => {
  const reviewSections = p.review_sections.map(s =>
    `      { heading: "${s.heading}", content: "${s.content.replace(/"/g, '\\"')}" }`
  ).join(",\n");

  return `  {
    id: "${p.id}",
    name: "${p.name}",
    brand: "${p.brand}",
    category: "${p.category}",
    description: "${p.description.replace(/"/g, '\\"')}",
    price: ${p.price},
    image_url: "${p.image_url}",
    affiliate_url: "${p.affiliate_url}",
    style_tags: ${JSON.stringify(p.style_tags)},
    color_tags: ${JSON.stringify(p.color_tags)},
    room_tags: ${JSON.stringify(p.room_tags)},
    dimensions: { width: ${p.dimensions.width}, depth: ${p.dimensions.depth}, height: ${p.dimensions.height} },
    in_stock: ${p.in_stock},
    discount_code: "${p.discount_code}",
    discount_percent: ${p.discount_percent},
    rating: ${p.rating},
    pros: ${JSON.stringify(p.pros)},
    cons: ${JSON.stringify(p.cons)},
    review_summary: "${p.review_summary.replace(/"/g, '\\"')}",
    review_sections: [
${reviewSections}
    ],
  }`;
}).join(",\n");

// Insert before the closing ];
content = content.replace(/\n\];[\s]*$/, `,\n${productStrings},\n];\n`);

writeFileSync(filePath, content, "utf-8");
console.log(`Added ${finalProducts.length} new products from ${Object.keys(brandConfig).length} brands.`);

// Verify
const newContent = readFileSync(filePath, "utf-8");
const totalProducts = (newContent.match(/id: "/g) || []).length;
console.log(`Total products now: ${totalProducts}`);
